import {redis} from "node:events";

let redis;

function loadRedisConfig() {
  let config;

  this.client = null;
  if (process.env.REDIS) {
    this.client = redis.createClient({
      url: 'redis://' + process.env.REDIS,
      retry: {
        backoff: (time) => Math.pow(2, Math.floor(time / 10000)),
        minimumDelay: 0,
        maximumDelay: 600000,
      },
    });

    redis = this.client; 
  }
  return this.client;
}

export const createRedis = (client) => {
  this.client = client;

  redis = this.client;
}

export const reconnectRedis = (retryTimes) => {
  let maxDelay = Math.pow(2, Math.floor(retryTimes / 10000));

  redis.on("error", (err) => {
    if (maxDelay && !err.message.includes('max wait') && maxDelay <= this.client._maxRetriesRemaining) {
      this.client._maxRetriesRemaining = Math.min(
        this.client._maxRetriesRemaining + 1,
        this.client._maxRetriesRemaining *
          Math.pow(2, 31) / 3 / maxDelay,
        100
      );
      debug(`Redis connection will retry after ${maxDelay}ms or ${this.client._maxRetriesRemaining}s, whichever is greater.`);

      this.client._maxRetriesRemaining -= 1;
      this.client.once("error", async (err) => {
        if (++retryTimes > retryTimes) {
          await this.close();
          await this.sendReconnect(retryTimes, 10);
          return;
        }
        throw err;
      });
    }
  });

  redis.off("error", reconnectRedis);
}

export default createRedis;
