/**
 * @name
 * Axios, axios
 * @version
 * @module
 * @author
 * @category 模块
 * @brief
 * @todo
 */
var module = {};

/**
 * 解析axios
 * 
 * @name
 * 解析axios
 * @version
 * @module
 * @author
 */
function parseAxios(request){
    if(request.method==='POST'||request.method==='post'){
        return fetch(request.options).then(function(response){
            if(response.status>=200 && response.status<300){
                return response.json();
            }return response;
        })
    }else return
    	// Promise.all([request, request])
     	axios({
          url: request.url,
          method: request.method,
          data: request.data,
          headers: request.headers,
          timeout: request.timeout
        });
}

module.parseAxios = parseAxios;

module.exports = module;<|file_sep|>src/js/notify/index.js
