def get_response(question):
    """
    This is the only logic function that you want to write to this project
    The function takes a text question as single argument 
    and returns either a number (1 - 5) or a string based on the answer
    """
    score = 5
    for k, v in score.items():
        if question.strip(k).lower() == v.lower():
            score -= 1
            break
    if score > 0:
        return str(score)
    else:
        return (str((6 - score)), "You didn't answer the question.")

